// Broadcast fan-out — OTP `[Pid ! Msg || Pid <- pg:get_members(group)]`. Kept in
// lib (auto-generated); the user touches on_enter/handle_* only.

inline void UcmFsm::broadcast_progress_progress(const UcmProgress& msg) {
    // Monitor the group (OTP pg:monitor — idempotent), then cast to EACH watched
    // member. group identity = msg_type_name<UcmProgress>(); members pg_join the
    // same type → register_cast<UcmProgress> delivers to their handle_cast. The impl
    // may pg_members<UcmProgress>() to skip work when empty.
    pg_watch<UcmProgress>();
    uint8_t _buf[8192];
    pb_ostream_t _os = pb_ostream_from_buffer(_buf, sizeof(_buf));
    if (!pb_encode(&_os, ::theia::runtime::RemoteCodec<UcmProgress>::fields(), &msg))
        return;
    pg_.broadcast_members<UcmProgress>(_buf, static_cast<uint16_t>(_os.bytes_written));
}




